import React, { useEffect, useState, useMemo, useRef } from 'react';
import { useLocation, Navigate } from 'react-router-dom';
import Header from './Header';
import NavDrawer from './NavDrawer';
import { useAppContext } from '../context/AppContext';
import { NAV_LINKS } from '../constants';

import SalesScreen from '../screens/SalesScreen';
import ReceiptsScreen from '../screens/ReceiptsScreen';
import ItemsScreen from '../screens/ItemsScreen';
import SettingsScreen from '../screens/SettingsScreen';
import ReportsScreen from '../screens/ReportsScreen';
import AboutScreen from '../screens/AboutScreen';

const SCREEN_TIMEOUT = 10 * 60 * 1000; // 10 Minutes
const SWIPE_THRESHOLD = 40; // Pixels to trigger open
const EDGE_ZONE = 50; // Pixels from left edge to start detection
const MAX_VERTICAL_SWIPE = 60; // Max vertical movement allowed during horizontal swipe

const KeepAliveScreen = React.memo(({ isVisible, children }: { isVisible: boolean, children: React.ReactNode }) => {
    return (
        <div 
            className={`flex flex-col h-full w-full absolute inset-0 bg-background transition-opacity duration-200 ${isVisible ? 'opacity-100 z-10' : 'opacity-0 z-[-1] pointer-events-none'}`}
            style={{ visibility: isVisible ? 'visible' : 'hidden' }}
        >
            {children}
        </div>
    );
});

const Layout: React.FC = () => {
  const { isDrawerOpen, openDrawer } = useAppContext();
  const location = useLocation();
  const { pathname } = location;

  // --- SWIPE GESTURE LOGIC ---
  const touchStart = useRef<{ x: number, y: number } | null>(null);

  const handleTouchStart = (e: React.TouchEvent) => {
    const x = e.touches[0].clientX;
    const y = e.touches[0].clientY;

    // Check if swipe started near the left edge
    if (x <= EDGE_ZONE) {
      touchStart.current = { x, y };
    } else {
      touchStart.current = null;
    }
  };

  const handleTouchMove = (e: React.TouchEvent) => {
    if (!touchStart.current) return;

    const y = e.touches[0].clientY;
    const x = e.touches[0].clientX;
    const deltaY = Math.abs(y - touchStart.current.y);
    const deltaX = x - touchStart.current.x;

    // If user is scrolling vertically or swiping backwards, cancel the gesture
    if (deltaY > MAX_VERTICAL_SWIPE || deltaX < -10) {
      touchStart.current = null;
    }
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart.current) return;

    const x = e.changedTouches[0].clientX;
    const deltaX = x - touchStart.current.x;

    // Only open if the swipe was significantly rightwards
    if (deltaX > SWIPE_THRESHOLD && !isDrawerOpen) {
      openDrawer();
    }
    touchStart.current = null;
  };

  // Screen management logic
  const [activeScreens, setActiveScreens] = useState<Record<string, number>>({ '/sales': Date.now() });

  useEffect(() => {
      setActiveScreens(prev => ({ ...prev, [pathname]: Date.now() }));
  }, [pathname]);

  useEffect(() => {
      const interval = setInterval(() => {
          const now = Date.now();
          setActiveScreens(prev => {
              const next = { ...prev };
              let changed = false;
              Object.keys(next).forEach(path => {
                  if (path !== '/sales' && path !== pathname && now - next[path] > SCREEN_TIMEOUT) {
                      delete next[path];
                      changed = true;
                  }
              });
              return changed ? next : prev;
          });
      }, 60000);
      return () => clearInterval(interval);
  }, [pathname]);

  const displayTitle = useMemo(() => {
      const currentLink = NAV_LINKS.find(link => pathname.startsWith(link.path));
      return currentLink ? currentLink.label : 'Restaurant POS';
  }, [pathname]);

  const showDefaultHeader = !['/sales', '/receipts', '/settings', '/items', '/reports', '/about'].includes(pathname); 

  if (!['/sales', '/receipts', '/items', '/settings', '/reports', '/about'].some(p => pathname.startsWith(p))) {
      return <Navigate to="/sales" replace />;
  }

  return (
    <div 
      className="relative h-screen w-full overflow-hidden bg-background text-text-primary flex flex-col"
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
    >
      {/* 
        Dedicated grab zone for left edge swipes. 
        High z-index ensures it captures touches over interactive elements.
      */}
      {!isDrawerOpen && (
        <div 
            className="fixed left-0 top-0 bottom-0 w-8 z-[100] touch-none" 
            onTouchStart={handleTouchStart}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleTouchEnd}
            aria-hidden="true"
        />
      )}

      {showDefaultHeader && <Header title={displayTitle} onMenuClick={openDrawer} />}
      <NavDrawer />

      <main className="flex-1 relative overflow-hidden">
        <KeepAliveScreen isVisible={pathname === '/sales'}><SalesScreen /></KeepAliveScreen>
        {activeScreens['/receipts'] && <KeepAliveScreen isVisible={pathname === '/receipts'}><ReceiptsScreen /></KeepAliveScreen>}
        {activeScreens['/reports'] && <KeepAliveScreen isVisible={pathname === '/reports'}><ReportsScreen /></KeepAliveScreen>}
        {activeScreens['/items'] && <KeepAliveScreen isVisible={pathname === '/items'}><ItemsScreen /></KeepAliveScreen>}
        {activeScreens['/settings'] && <KeepAliveScreen isVisible={pathname === '/settings'}><SettingsScreen /></KeepAliveScreen>}
        {activeScreens['/about'] && <KeepAliveScreen isVisible={pathname === '/about'}><AboutScreen /></KeepAliveScreen>}
      </main>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { SettingsCategory } from '../../screens/SettingsScreen';
import { useAppContext } from '../../context/AppContext';
import { Printer, Table, PaymentType } from '../../types';

// Cards
import StoreInfoCard from './cards/StoreInfoCard';
import PaymentsTaxesCard from './cards/PaymentsTaxesCard';
import AccountStaffCard from './cards/AccountStaffCard';
import TablesCard from './cards/TablesCard';
import AppearanceCard from './cards/AppearanceCard';
import PrintersCard from './cards/PrintersCard';
import SecurityCard from './cards/SecurityCard';
import DataManagementCard from './cards/DataManagementCard';
import NotificationsCard from './cards/NotificationsCard';

// Modals - FIXED: Using relative paths to avoid module specifier errors
import AddPrinterModal from '../modals/AddPrinterModal';
import TableFormModal from '../modals/TableFormModal';
import AddPaymentTypeModal from '../modals/AddPaymentTypeModal';

// Utils
import { testPrint } from '../../utils/printerHelper';

interface SettingsContentProps {
    activeCategory: SettingsCategory;
}

const SettingsContent: React.FC<SettingsContentProps> = ({ activeCategory }) => {
    const { 
        settings, updateSettings, theme, setTheme, user, signOut, 
        paymentTypes, updatePaymentType, removePaymentType, addPaymentType,
        tables, setTables, addTable, updateTable, removeTable,
        printers, addPrinter, removePrinter,
        exportData 
    } = useAppContext();

    // State for modals and actions
    const [isAddPrinterModalOpen, setIsAddPrinterModalOpen] = useState(false);
    const [testingPrinterId, setTestingPrinterId] = useState<string | null>(null);
    const [isTableModalOpen, setIsTableModalOpen] = useState(false);
    const [editingTable, setEditingTable] = useState<Table | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);

    // --- Printer Handlers ---
    const handleTestPrinter = async (printer: Printer) => {
        setTestingPrinterId(printer.id);
        const result = await testPrint(printer, settings);
        if (!result.success) {
            alert(`Test Print Failed: ${result.message}`);
        }
        setTestingPrinterId(null);
    };

    const handleSavePrinter = async (printer: Printer) => {
        try {
            await addPrinter(printer);
            setIsAddPrinterModalOpen(false);
        } catch (error: any) {
            if (error.message?.includes('quota')) {
                alert("Cloud storage quota exceeded. Printer saved locally but might not sync.");
            } else {
                alert("Failed to save printer. Check your internet connection.");
            }
        }
    };

    // --- Table Handlers ---
    const handleOpenAddTable = () => {
        setEditingTable(null);
        setIsTableModalOpen(true);
    };

    const handleOpenEditTable = (table: Table) => {
        setEditingTable(table);
        setIsTableModalOpen(true);
    };

    const handleSaveTable = async (name: string) => {
        try {
            if (editingTable) {
                await updateTable({ ...editingTable, name });
            } else {
                await addTable(name);
            }
            setIsTableModalOpen(false);
            setEditingTable(null);
        } catch (error: any) {
            alert("Error saving table. Your Firebase quota may be finished.");
        }
    };

    // --- Payment Type Handlers ---
    const handleSavePaymentType = async (paymentType: Omit<PaymentType, 'id' | 'enabled' | 'type'>) => {
        try {
            await addPaymentType(paymentType);
            setIsPaymentModalOpen(false);
        } catch (error) {
            alert("Error adding payment type.");
        }
    };

    const wrapCard = (children: React.ReactNode) => (
        <div className="bg-surface rounded-2xl shadow-sm border border-border overflow-hidden">
            {children}
        </div>
    );

    return (
        <>
            {(() => {
                switch (activeCategory) {
                    case 'store_info':
                        return wrapCard(<StoreInfoCard settings={settings} updateSettings={updateSettings} />);
                    case 'payments_taxes':
                        return wrapCard(
                            <PaymentsTaxesCard 
                                settings={settings} 
                                updateSettings={updateSettings} 
                                paymentTypes={paymentTypes}
                                onAddPayment={() => setIsPaymentModalOpen(true)}
                                onTogglePayment={(pt) => updatePaymentType({...pt, enabled: !pt.enabled})}
                                onRemovePayment={removePaymentType}
                            />
                        );
                    case 'account':
                        return wrapCard(<AccountStaffCard user={user} signOut={signOut} />);
                    case 'tables':
                        return wrapCard(
                            <TablesCard 
                                tables={tables} 
                                setTables={setTables} 
                                onAdd={handleOpenAddTable} 
                                onEdit={handleOpenEditTable} 
                                onRemove={removeTable} 
                            />
                        );
                    case 'appearance':
                        return wrapCard(<AppearanceCard theme={theme} setTheme={setTheme} />);
                    case 'printers':
                        return wrapCard(
                            <PrintersCard 
                                printers={printers} 
                                onAdd={() => setIsAddPrinterModalOpen(true)} 
                                onTest={handleTestPrinter} 
                                onRemove={(p) => removePrinter(p.id)} 
                                testingPrinterId={testingPrinterId} 
                            />
                        );
                    case 'security':
                        return wrapCard(<SecurityCard settings={settings} updateSettings={updateSettings} />);
                    case 'data':
                        return wrapCard(<DataManagementCard onExport={exportData} onImport={() => {}} />);
                    case 'notifications':
                        return wrapCard(<NotificationsCard settings={settings} updateSettings={updateSettings} />);
                    case 'preferences':
                        return wrapCard(
                            <div className="p-6">
                                <h3 className="text-lg font-bold mb-4">Regional Settings</h3>
                                <div className="space-y-4">
                                    <div className="flex items-center justify-between">
                                        <span className="text-sm font-medium">Currency</span>
                                        <span className="text-sm font-bold text-primary">{settings.currencySymbol || '₹'}</span>
                                    </div>
                                    <div className="flex items-center justify-between">
                                        <span className="text-sm font-medium">Language</span>
                                        <span className="text-sm text-text-secondary">English (United Kingdom)</span>
                                    </div>
                                </div>
                            </div>
                        );
                    default:
                        return null;
                }
            })()}

            <AddPrinterModal 
                isOpen={isAddPrinterModalOpen}
                onClose={() => setIsAddPrinterModalOpen(false)}
                onSave={handleSavePrinter}
            />

            <TableFormModal
                isOpen={isTableModalOpen}
                onClose={() => setIsTableModalOpen(false)}
                onSave={handleSaveTable}
                initialData={editingTable}
            />

            <AddPaymentTypeModal
                isOpen={isPaymentModalOpen}
                onClose={() => setIsPaymentModalOpen(false)}
                onSave={handleSavePaymentType}
            />
        </>
    );
};

