import React from 'react';
import { PaymentType } from '../../../types';
import { PaymentMethodIcon, ArrowLeftIcon, SplitIcon, UserIcon, TrashIcon } from '../../../constants';

interface PaymentWorkspaceProps {
    onBack: () => void;
    total: number;
    otherPaymentTypes: PaymentType[];
    cashPaymentType: PaymentType | undefined;
    inputRef: React.RefObject<HTMLInputElement>;
    cashTendered: string;
    handleFocus: (e: React.FocusEvent<HTMLInputElement>) => void;
    handleCashChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    handleProcessCashPayment: () => void;
    handleProcessOtherPayment: (methodName: string) => void;
    uniqueQuickCash: number[];
    onProcessPayment: (method: string, tendered: number) => void;
    onSplitClick: () => void;
}

/**
 * The main interactive area for processing payments.
 * Allows selecting Cash, Custom Methods (UPI, Card), or switching to Split Payment.
 */
const PaymentWorkspace: React.FC<PaymentWorkspaceProps> = ({
    onBack, total, otherPaymentTypes, cashPaymentType,
    inputRef, cashTendered, handleFocus, handleCashChange, handleProcessCashPayment, handleProcessOtherPayment,
    uniqueQuickCash, onProcessPayment, onSplitClick
}) => {
    // Helper for numpad
    const appendNumber = (num: string) => {
        const setVal = (val: string) => {
            if (inputRef.current) {
                const nativeSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value')?.set;
                nativeSetter?.call(inputRef.current, val);
                inputRef.current.dispatchEvent(new Event('input', { bubbles: true }));
            }
        };

        if (cashTendered === '0' && num !== '.') {
            setVal(num);
        } else if (num === '.' && cashTendered.includes('.')) {
            return;
        } else if (num === '.' && !cashTendered) {
            setVal('0.');
        } else {
            // Check decimal limit (2 places)
            const parts = cashTendered.split('.');
            if (parts.length > 1 && parts[1].length >= 2) return;
            setVal(cashTendered + num);
        }
    };

    const backspace = () => {
        if (inputRef.current) {
            const newVal = cashTendered.slice(0, -1);
            const nativeSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value')?.set;
            nativeSetter?.call(inputRef.current, newVal);
            inputRef.current.dispatchEvent(new Event('input', { bubbles: true }));
        }
    };

    return (
    <div className="flex-1 flex flex-col h-full bg-background relative">
      {/* Mobile Header */}
      <header className="flex-shrink-0 h-16 flex items-center justify-between px-4 bg-surface border-b border-border md:hidden">
        <button onClick={onBack} className="flex items-center gap-2 text-text-secondary hover:text-text-primary font-semibold">
          <ArrowLeftIcon className="h-5 w-5" />
          Back
        </button>
        <span className="font-bold text-lg">Checkout</span>
        <button 
            onClick={onSplitClick} 
            className="flex items-center gap-1 bg-surface-muted text-text-primary px-3 py-1.5 rounded-lg border border-border hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors text-xs font-bold uppercase tracking-wide active:opacity-70"
        >
            <SplitIcon className="h-4 w-4" /> Split
        </button>
      </header>

      {/* Desktop Header */}
      <header className="hidden md:flex flex-shrink-0 h-16 items-center justify-between px-6 border-b border-border bg-surface">
        <div className="flex items-center gap-4">
            <button onClick={onBack} className="flex items-center gap-2 text-text-secondary hover:text-text-primary font-semibold px-3 py-1.5 rounded-lg hover:bg-surface-muted transition-colors active:opacity-80">
            <ArrowLeftIcon className="h-5 w-5" />
            Back to Sales
            </button>
            <button 
                onClick={onSplitClick} 
                className="flex items-center gap-2 bg-white dark:bg-gray-800 text-text-primary px-4 py-2 rounded-lg border border-border hover:border-primary/50 hover:text-primary transition-all shadow-sm font-bold text-sm active:bg-surface-muted"
            >
                <SplitIcon className="h-4 w-4" />
                SPLIT PAYMENT
            </button>
        </div>
        <div className="flex items-center gap-2">
             <UserIcon className="h-5 w-5 text-text-muted" />
             <span className="text-sm text-text-secondary">Cashier</span>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto p-4 md:p-8">
        <div className="max-w-3xl mx-auto flex flex-col items-center">
            {/* Total Display */}
            <div className="mb-6 text-center py-1">
                <p className="text-xs text-text-muted uppercase tracking-wider mb-1 font-bold">Total Payable Amount</p>
                <div className="flex items-baseline justify-center gap-1 text-5xl md:text-7xl font-bold font-mono text-text-primary tracking-tight">
                    <span className="text-3xl md:text-5xl text-text-muted font-normal">₹</span>
                    {total.toFixed(2)}
                </div>
            </div>

            <div className="w-full space-y-6">
                {/* 1. Other Methods Grid (Top Priority) */}
                <div>
                     <div className="grid grid-cols-1 gap-3">
                        {otherPaymentTypes.map(pt => (
                            <button 
                            key={pt.id} 
                            onClick={() => handleProcessOtherPayment(pt.name)} 
                            className="bg-emerald-500 text-white font-bold rounded-xl shadow-md hover:bg-emerald-600 transition-all flex items-center justify-center gap-3 active:opacity-80 py-4 w-full"
                            >
                            <PaymentMethodIcon iconName={pt.icon} className="h-6 w-6 text-white/90"/>
                            <span>{pt.name}</span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Divider */}
                {cashPaymentType && otherPaymentTypes.length > 0 && (
                    <div className="flex items-center gap-4">
                        <hr className="flex-grow border-border" />
                        <span className="text-xs font-bold text-text-muted uppercase tracking-wider">OR</span>
                        <hr className="flex-grow border-border" />
                    </div>
                )}

                {/* 2. Cash Section */}
                {cashPaymentType && (
                    <div className="bg-surface p-4 rounded-2xl border border-border shadow-sm">
                        <label className="block text-sm font-bold text-text-secondary mb-2">Cash Payment</label>
                        <div className="flex flex-col md:flex-row items-stretch gap-3 mb-3">
                            <div className="relative flex-grow">
                                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-text-muted font-bold text-xl">₹</span>
                                <input 
                                    ref={inputRef} 
                                    type="text" 
                                    inputMode="decimal" 
                                    value={cashTendered} 
                                    onFocus={handleFocus} 
                                    onChange={handleCashChange} 
                                    onKeyDown={(e) => e.key === 'Enter' && handleProcessCashPayment()}
                                    className="w-full h-14 pl-10 pr-4 rounded-xl border border-border bg-background text-2xl font-bold font-mono focus:ring-2 focus:ring-primary focus:border-primary text-text-primary"
                                />
                            </div>
                            <button
                                onClick={handleProcessCashPayment}
                                className="bg-primary text-primary-content font-bold px-8 rounded-xl shadow-md hover:bg-primary-hover active:opacity-80 transition-opacity flex items-center justify-center min-h-[56px]"
                            >
                                Exact Cash
                            </button>
                        </div>

                        {/* Quick Cash Options */}
                        {uniqueQuickCash.length > 0 && (
                            <div className="flex flex-wrap gap-2 mb-4">
                                {uniqueQuickCash.map(amount => (
                                    <button
                                        key={amount}
                                        onClick={() => onProcessPayment('Cash', amount)}
                                        className="px-4 py-2 bg-surface-muted border border-border rounded-lg text-sm font-bold text-text-secondary hover:bg-primary/10 hover:text-primary hover:border-primary transition-colors active:bg-primary/20"
                                    >
                                        ₹{amount}
                                    </button>
                                ))}
                            </div>
                        )}

                        {/* Numpad */}
                        <div className="grid grid-cols-3 gap-3">
                            {[1, 2, 3, 4, 5, 6, 7, 8, 9].map((num) => (
                                <button
                                    key={num}
                                    onClick={() => appendNumber(num.toString())}
                                    className="py-6 text-2xl font-bold bg-surface border border-border rounded-xl shadow-sm hover:bg-surface-muted active:bg-surface-muted/80 active:border-primary/50 transition-colors text-text-primary"
                                >
                                    {num}
                                </button>
                            ))}
                            <button
                                onClick={() => appendNumber('.')}
                                className="py-6 text-2xl font-bold bg-surface border border-border rounded-xl shadow-sm hover:bg-surface-muted active:bg-surface-muted/80 active:border-primary/50 transition-colors text-text-primary"
                            >
                                .
                            </button>
                            <button
                                onClick={() => appendNumber('0')}
                                className="py-6 text-2xl font-bold bg-surface border border-border rounded-xl shadow-sm hover:bg-surface-muted active:bg-surface-muted/80 active:border-primary/50 transition-colors text-text-primary"
                            >
                                0
                            </button>
                            <button
                                onClick={backspace}
                                className="py-6 text-xl font-bold bg-surface-muted border border-border rounded-xl shadow-sm hover:bg-gray-200 dark:hover:bg-gray-700 active:opacity-70 transition-opacity text-text-secondary flex items-center justify-center"
                            >
                                <TrashIcon className="h-6 w-6" />
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
    );
};

export default PaymentWorkspace;

import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import type { OrderItem, SavedTicket, Item, CustomGrid, SplitPaymentDetail, Receipt } from '../types';
import { useAppContext } from '../context/AppContext';
import { useDebounce } from '../hooks/useDebounce';
import { printBill } from '../utils/printerHelper';

// Modals and Child Components
import SaveTicketModal from '../components/modals/SaveTicketModal';
import OpenTicketsModal from '../components/modals/OpenTicketsModal';
import ManageGridsModal from '../components/modals/ManageGridsModal';
import SelectItemModal from '../components/modals/SelectItemModal';
import AddGridModal from '../components/modals/AddGridModal';
import ConfirmModal from '../components/modals/ConfirmModal';
import PriceInputModal from '../components/modals/PriceInputModal';
import SalesHeader from '../components/sales/SalesHeader';
import ItemGrid from '../components/sales/ItemGrid';
import CategoryTabs from '../components/sales/CategoryTabs';
import Ticket from '../components/sales/Ticket';
import ChargeScreen from '../components/sales/ChargeScreen';
import { ItemsIcon, SalesIcon } from '../constants';

type SalesView = 'grid' | 'payment';

// UUID Generator Fallback
const generateId = () => crypto.randomUUID ? crypto.randomUUID() : `G${Date.now()}`;

// --- SEARCH WORKER CODE ---
const SEARCH_WORKER_CODE = `
self.onmessage = function(e) {
    const { items, query } = e.data;

    if (!query || !query.trim()) {
        self.postMessage([]);
        return;
    }

    const lowerQuery = query.trim().toLowerCase();

    // Perform filtering off-main-thread
    const results = items.filter(item => {
        const nameMatch = item.name.toLowerCase().includes(lowerQuery);
        const categoryMatch = item.category ? item.category.toLowerCase().includes(lowerQuery) : false;
        return nameMatch || categoryMatch;
    });

    self.postMessage(results);
};
`;

const SalesScreen: React.FC = () => {
  const { 
      openDrawer, settings, printers, addReceipt, openAddPrinterModal,
      items, customGrids, addCustomGrid, updateCustomGrid, setCustomGrids,
      savedTickets, saveTicket, removeTicket,
      // Global Ticket State
      currentOrder, addToOrder, removeFromOrder, deleteLineItem, 
      updateOrderItemQuantity, clearOrder, loadOrder,
      // Global View State
      activeGridId, setActiveGridId
  } = useAppContext();
  const navigate = useNavigate();
  const location = useLocation();
  const isActive = location.pathname === '/sales';

  // --- 1. DEVICE & LAYOUT DETECTION ---
  const getGridSize = () => 20;
  const [gridSize, setGridSize] = useState(getGridSize());

  useEffect(() => {
      const handleResize = () => setGridSize(getGridSize());
      window.addEventListener('resize', handleResize);
      return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Main screen view state
  const [salesView, setSalesView] = useState<SalesView>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const debouncedSearchQuery = useDebounce(searchQuery, 300);

  // Search Results from Worker
  const [workerSearchResults, setWorkerSearchResults] = useState<Item[]>([]);
  const searchWorkerRef = useRef<Worker | null>(null);

  // Ticket management state
  const [editingTicket, setEditingTicket] = useState<SavedTicket | null>(null);
  const [editingQuantityItemId, setEditingQuantityItemId] = useState<string | null>(null);
  const [tempQuantity, setTempQuantity] = useState<string>('');

  // State to track if we should print after a successful save
  const [pendingPrintAction, setPendingPrintAction] = useState(false);

  // Grid Editing State
  const [isGridEditing, setIsGridEditing] = useState(false);

  // Payment state
  const [paymentResult, setPaymentResult] = useState<{ method: string, change: number, receiptId: string, date: Date } | null>(null);

  // Pagination & Scroll State
  const [displayLimit, setDisplayLimit] = useState(40);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const loadMoreRef = useRef<HTMLDivElement>(null);

  // Modal states
  const [isManageGridsModalOpen, setIsManageGridsModalOpen] = useState(false);
  const [isSaveModalOpen, setIsSaveModalOpen] = useState(false);
  const [isOpenTicketsModalOpen, setIsOpenTicketsModalOpen] = useState(false);
  const [isSelectItemModalOpen, setIsSelectItemModalOpen] = useState(false);
  const [isAddGridModalOpen, setIsAddGridModalOpen] = useState(false);
  const [assigningSlot, setAssigningSlot] = useState<{gridId: string, slotIndex: number} | null>(null);

  // Variable Price State
  const [variablePriceItem, setVariablePriceItem] = useState<Item | null>(null);

  const [confirmModalState, setConfirmModalState] = useState<{
      isOpen: boolean;
      title: string;
      message: React.ReactNode;
      onConfirm: () => void;
      confirmText?: string;
      confirmButtonClass?: string;
  }>({ isOpen: false, title: '', message: '', onConfirm: () => {} });

  const [isTicketVisible, setIsTicketVisible] = useState(false);

  // Initialize Search Worker
  useEffect(() => {
      const blob = new Blob([SEARCH_WORKER_CODE], { type: 'application/javascript' });
      const worker = new Worker(URL.createObjectURL(blob));
      searchWorkerRef.current = worker;

      worker.onmessage = (e) => {
          setWorkerSearchResults(e.data);
      };

      return () => {
          worker.terminate();
      };
  }, []);

  // Post messages to worker when query or items change
  useEffect(() => {
      if (searchWorkerRef.current && debouncedSearchQuery.trim()) {
          searchWorkerRef.current.postMessage({
              items: items,
              query: debouncedSearchQuery
          });
      } else {
          setWorkerSearchResults([]);
      }
  }, [debouncedSearchQuery, items]);

  // Force scroll container reflow
  useEffect(() => {
    if (isActive && scrollContainerRef.current) {
        scrollContainerRef.current.scrollTop = 0;
    }
  }, [isActive]);

  // Reset pagination when category changes
  useEffect(() => {
    setDisplayLimit(40);
    setIsGridEditing(false);
    if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTop = 0;
    }
  }, [activeGridId, debouncedSearchQuery]);

  // --- ITEM CLICK HANDLER ---
  const handleItemClick = useCallback((item: Item) => {
      if (item.price === 0) {
          setVariablePriceItem(item);
      } else {
          addToOrder(item);
      }
  }, [addToOrder]);

  const handleVariablePriceConfirm = (price: number) => {
      if (variablePriceItem) {
          const tempItem = { ...variablePriceItem, price: price };
          addToOrder(tempItem);
          setVariablePriceItem(null);
      }
  };

  const handleQuantityClick = useCallback((item: OrderItem) => {
    setEditingQuantityItemId(item.lineItemId);
    setTempQuantity(item.quantity.toString());
  }, []);

  const handleQuantityChangeCommit = useCallback(() => {
    if (!editingQuantityItemId) return;
    const newQuantity = parseInt(tempQuantity, 10);
    updateOrderItemQuantity(editingQuantityItemId, newQuantity);
    setEditingQuantityItemId(null);
  }, [editingQuantityItemId, tempQuantity, updateOrderItemQuantity]);

  const handleQuantityInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
      if (/^\d*$/.test(e.target.value)) {
          setTempQuantity(e.target.value);
      }
  }, []);

  const handleQuantityInputKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') handleQuantityChangeCommit(); 
      else if (e.key === 'Escape') setEditingQuantityItemId(null);
  }, [handleQuantityChangeCommit]);

  const handleTicketClose = useCallback(() => setIsTicketVisible(false), []);
  const handleChargeClick = useCallback(() => setSalesView('payment'), []);
  const handleOpenTicketsClick = useCallback(() => setIsOpenTicketsModalOpen(true), []);

  const handleSaveTicketClick = useCallback(() => {
      setPendingPrintAction(false); 
      setIsSaveModalOpen(true);
  }, []);

  const subtotal = useMemo(() => currentOrder.reduce((sum, item) => sum + item.price * item.quantity, 0), [currentOrder]);
  const tax = useMemo(() => settings.taxEnabled ? subtotal * (settings.taxRate / 100) : 0, [subtotal, settings]);
  const total = useMemo(() => subtotal + tax, [subtotal, tax]);

  const handleProcessPayment = useCallback((method: string, tendered: number, splitDetails?: SplitPaymentDetail[]) => {
    if (editingTicket) removeTicket(editingTicket.id);
    const receiptId = `R${Date.now()}`;
    const receiptDate = new Date();

    const optimizedItems = currentOrder.map(item => ({
        ...item,
        imageUrl: '' // Strip base64 string
    }));

    const newReceipt: Receipt = { 
        id: receiptId, 
        date: receiptDate, 
        items: optimizedItems, 
        total, 
        paymentMethod: method 
    };

    if (splitDetails && splitDetails.length > 0) {
        newReceipt.splitDetails = splitDetails;
    }

    addReceipt(newReceipt);
    setPaymentResult({ method, change: tendered - total, receiptId, date: receiptDate });
  }, [addReceipt, currentOrder, editingTicket, removeTicket, total]);

  const handleNewSale = useCallback(() => {
    setSalesView('grid'); 
    setPaymentResult(null); 
    clearOrder(); 
    setEditingTicket(null);
  }, [clearOrder]);

  const itemsForDisplay = useMemo<(Item | null)[]>(() => {
    if (debouncedSearchQuery.trim()) return workerSearchResults;
    if (activeGridId === 'All') return items;

    const grid = customGrids.find(g => g.id === activeGridId);
    if (grid) {
        const sourceIds = Array.isArray(grid.itemIds) ? grid.itemIds : [];
        const finalItemIds = new Array(gridSize).fill(null);
        for(let i = 0; i < Math.min(sourceIds.length, gridSize); i++) {
            finalItemIds[i] = sourceIds[i];
        }
        return finalItemIds.map(itemId => items.find(i => i.id === itemId) || null);
    }
    return new Array(gridSize).fill(null);
  }, [activeGridId, items, customGrids, debouncedSearchQuery, workerSearchResults, gridSize]);

  const paginatedItems = useMemo(() => {
      if (activeGridId !== 'All' && !debouncedSearchQuery.trim()) return itemsForDisplay;
      return itemsForDisplay.slice(0, displayLimit);
  }, [itemsForDisplay, displayLimit, activeGridId, debouncedSearchQuery]);

  useEffect(() => {
    if ((activeGridId !== 'All' && !debouncedSearchQuery.trim()) || paginatedItems.length >= itemsForDisplay.length) return; 

    const observer = new IntersectionObserver(
        (entries) => {
            if (entries[0].isIntersecting) {
                setDisplayLimit((prev) => prev + 20);
            }
        },
        { threshold: 0.1, rootMargin: '100px' }
    );

    if (loadMoreRef.current) observer.observe(loadMoreRef.current);
    return () => observer.disconnect();
  }, [paginatedItems.length, itemsForDisplay.length, activeGridId, debouncedSearchQuery]);


  const handleAddNewGrid = useCallback(() => setIsAddGridModalOpen(true), []);
  const handleSaveNewGrid = useCallback((name: string) => {
      const newGridId = generateId();
      addCustomGrid({ id: newGridId, name, itemIds: new Array(gridSize).fill(null) });
      setIsAddGridModalOpen(false);
      // Auto-switch to newly created grid and enter edit mode for better UX
      setActiveGridId(newGridId);
      setIsGridEditing(true);
  }, [addCustomGrid, gridSize, setActiveGridId]);

  const handleSaveGrids = useCallback((newGrids: CustomGrid[]) => {
      setCustomGrids(newGrids);
      setIsManageGridsModalOpen(false);
      if (activeGridId !== 'All' && !newGrids.some(g => g.id === activeGridId)) {
          setActiveGridId('All');
      }
  }, [activeGridId, setCustomGrids, setActiveGridId]);

  const handleOpenSelectItemModal = useCallback((slotIndex: number) => {
      if (activeGridId === 'All') return;
      setAssigningSlot({ gridId: activeGridId, slotIndex });
      setIsSelectItemModalOpen(true);
  }, [activeGridId]);

  const handleSelectItem = useCallback((item: Item) => {
      if (!assigningSlot) return;
      const gridToUpdate = customGrids.find(g => g.id === assigningSlot.gridId);
      if (gridToUpdate) {
          const sourceIds = Array.isArray(gridToUpdate.itemIds) ? gridToUpdate.itemIds : [];
          const newItemIds = [...sourceIds];
          while (newItemIds.length < gridSize) newItemIds.push(null);

          newItemIds[assigningSlot.slotIndex] = item.id;
          updateCustomGrid({ ...gridToUpdate, itemIds: newItemIds });
      }
      setIsSelectItemModalOpen(false);
      setAssigningSlot(null);
  }, [assigningSlot, customGrids, updateCustomGrid, gridSize]);

  const handleRemoveItemFromGrid = useCallback((slotIndex: number) => {
    if (activeGridId === 'All') return;
    const gridToUpdate = customGrids.find(g => g.id === activeGridId);
    if (gridToUpdate) {
        const sourceIds = Array.isArray(gridToUpdate.itemIds) ? gridToUpdate.itemIds : [];
        const newItemIds = [...sourceIds];
        while (newItemIds.length < gridSize) newItemIds.push(null);

        newItemIds[slotIndex] = null;
        updateCustomGrid({ ...gridToUpdate, itemIds: newItemIds });
    }
  }, [activeGridId, customGrids, updateCustomGrid, gridSize]);

  const handleClearTicket = useCallback(() => {
    clearOrder();
    setEditingTicket(null);
    setEditingQuantityItemId(null);
  }, [clearOrder]);

  const handleLoadTicket = (ticket: SavedTicket) => {
      const loadAction = () => {
          loadOrder(ticket.items);
          setEditingTicket(ticket);
          setIsOpenTicketsModalOpen(false);
          if (window.innerWidth < 768) {
              setIsTicketVisible(true);
          }
      };
      if (currentOrder.length > 0) {
          setConfirmModalState({
              isOpen: true,
              title: 'Replace Current Order?',
              message: 'Loading a saved ticket will replace your current unsaved order. Are you sure?',
              onConfirm: loadAction,
              confirmText: 'Yes, Load Ticket',
              confirmButtonClass: 'bg-amber-500 hover:bg-amber-600'
          });
      } else {
          loadAction();
      }
  };

  const performPrint = useCallback(async (ticketItems: OrderItem[], ticketName: string) => {
      const pSubtotal = ticketItems.reduce((sum, item) => sum + item.price * item.quantity, 0);
      const pTax = settings.taxEnabled ? pSubtotal * (settings.taxRate / 100) : 0;
      const pTotal = pSubtotal + pTax;

      const printer = printers.find(p => p.interfaceType === 'Bluetooth') || printers[0];
      if (!printer) {
          openAddPrinterModal();
          return;
      }

      const result = await printBill({
          items: ticketItems,
          total: pTotal, subtotal: pSubtotal, tax: pTax,
          ticketName: ticketName,
          settings, printer,
      });
      if (!result.success) {
          alert(`Print Failed: ${result.message}`);
      }
  }, [settings, printers, openAddPrinterModal]);

  const handlePrintRequest = useCallback(async () => {
    if (currentOrder.length === 0) {
        alert("Ticket is empty. Nothing to print.");
        return;
    }

    // Workflow for a saved ticket (editingTicket exists)
    if (editingTicket) {
        // 1. Auto-save any changes made to the ticket
        const updatedTicket = { ...editingTicket, items: [...currentOrder], lastModified: Date.now() };
        await saveTicket(updatedTicket);

        // 2. Print the bill for the updated ticket
        await performPrint(updatedTicket.items, updatedTicket.name);

        // 3. Clear the workspace for a new sale, ready for the next customer
        clearOrder();
        setEditingTicket(null);
        if (window.innerWidth < 768) {
            setIsTicketVisible(false); // Hide mobile ticket view
        }
    } else {
        // Workflow for a new, unsaved ticket: prompt to save first
        setPendingPrintAction(true);
        setIsSaveModalOpen(true);
    }
  }, [editingTicket, currentOrder, saveTicket, clearOrder, performPrint]);

  const handleSaveTicketComplete = (name: string) => {
      const itemsToSave = [...currentOrder];
      saveTicket({ id: `T${Date.now()}`, name, items: itemsToSave }); 
      clearOrder(); 
      setEditingTicket(null); 
      setIsSaveModalOpen(false); 
      if (pendingPrintAction) {
          performPrint(itemsToSave, name);
          setPendingPrintAction(false); 
      }
  };

  const handlePrimarySaveAction = useCallback(() => {
      if (editingTicket) {
          saveTicket({ ...editingTicket, items: currentOrder });
          clearOrder();
          setEditingTicket(null);
          setIsTicketVisible(false);
      } else {
          setPendingPrintAction(false);
          setIsSaveModalOpen(true);
      }
  }, [editingTicket, currentOrder, saveTicket, clearOrder]);

  if (salesView === 'payment') {
    return <ChargeScreen total={total} tax={tax} subtotal={subtotal} onBack={() => setSalesView('grid')} onProcessPayment={handleProcessPayment} onNewSale={handleNewSale} paymentResult={paymentResult} orderItems={currentOrder} />;
  }

  const isViewingAll = activeGridId === 'All' || debouncedSearchQuery.trim().length > 0;

  return (
    <div className="flex h-full w-full bg-background font-sans relative overflow-hidden">
      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <SalesHeader 
            openDrawer={openDrawer} 
            onSearchChange={setSearchQuery} 
            searchQuery={searchQuery} 
            storeName={settings.storeName}
        />

        <div className="flex-1 relative overflow-hidden">
            <div 
              ref={scrollContainerRef} 
              className="absolute inset-0 overflow-y-auto overflow-x-hidden p-2 md:p-4 scroll-smooth"
              style={{ WebkitOverflowScrolling: 'touch', transform: 'translateZ(0)' }}
            >
              {items.length === 0 && !debouncedSearchQuery.trim() ? (
                <div className="flex flex-col items-center justify-center h-full text-center text-text-secondary p-4">
                  <div className="max-w-md">
                    <ItemsIcon className="h-16 w-16 mx-auto text-gray-300 dark:text-gray-600" />
                    <h2 className="mt-4 text-xl font-semibold text-text-primary">Your Menu is Empty</h2>
                    <button
                      onClick={() => navigate('/items')}
                      className="mt-6 px-6 py-3 bg-primary text-primary-content font-bold rounded-lg hover:bg-primary-hover shadow-md"
                    >
                      Add Items
                    </button>
                  </div>
                </div>
              ) : (
                <div className={`pb-24 md:pb-0 ${!isViewingAll ? 'md:h-full' : 'md:pb-4'}`}>
                    <ItemGrid
                    itemsForDisplay={paginatedItems}
                    mode={isViewingAll ? 'all' : 'grid'}
                    onAddItemToOrder={handleItemClick}
                    onAssignItem={handleOpenSelectItemModal}
                    onRemoveItem={handleRemoveItemFromGrid}
                    isEditing={!isViewingAll && isGridEditing}
                    loadMoreRef={isViewingAll ? loadMoreRef : undefined}
                    />
                </div>
              )}
            </div>
        </div>

        {currentOrder.length > 0 && (
            <div className="md:hidden absolute bottom-[50px] left-0 right-0 p-4 z-50 pointer-events-none">
                <button 
                    onClick={() => setIsTicketVisible(true)}
                    className="w-full bg-primary text-primary-content rounded-xl shadow-xl shadow-primary/30 flex items-center justify-between p-4 active:opacity-90 transition-opacity pointer-events-auto"
                >
                    <div className="flex items-center gap-3">
                        <span className="bg-white/20 px-2.5 py-1 rounded-md text-sm font-bold backdrop-blur-sm">
                            {currentOrder.reduce((acc, item) => acc + item.quantity, 0)}
                        </span>
                        <span className="font-bold text-sm uppercase tracking-wide">View Cart</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <span className="font-bold text-lg">₹{total.toFixed(2)}</span>
                        <SalesIcon className="h-5 w-5 opacity-80" />
                    </div>
                </button>
            </div>
        )}

        <div className="bg-surface border-t border-border z-40 flex-shrink-0 relative shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
             <CategoryTabs
                grids={customGrids}
                activeGridId={activeGridId}
                setActiveGridId={setActiveGridId}
                onAddNew={handleAddNewGrid}
                onManage={() => setIsManageGridsModalOpen(true)}
                isSearchActive={debouncedSearchQuery.trim().length > 0}
                searchResultsCount={itemsForDisplay.length}
                searchQuery={searchQuery}
                isEditing={isGridEditing}
                onToggleEditMode={() => setIsGridEditing(prev => !prev)}
              />
        </div>
      </div>

      <div 
        className={`
            fixed inset-0 z-[60] bg-background flex flex-col
            transition-transform duration-300 ease-out will-change-transform
            md:static md:z-auto md:w-[320px] lg:w-[380px] md:border-l md:border-border md:translate-y-0
            ${isTicketVisible ? 'translate-y-0' : 'translate-y-full'}
        `}
      >
        <Ticket
          className="w-full h-full flex flex-col"
          onClose={handleTicketClose} 
          currentOrder={currentOrder} 
          editingTicket={editingTicket}
          savedTickets={savedTickets} 
          settings={settings} 
          total={total} 
          subtotal={subtotal} 
          tax={tax}
          editingQuantityItemId={editingQuantityItemId} 
          tempQuantity={tempQuantity} 
          setEditingQuantityItemId={setEditingQuantityItemId}
          setTempQuantity={setTempQuantity} 
          removeFromOrder={removeFromOrder} 
          deleteLineItem={deleteLineItem}
          updateOrderItemQuantity={updateOrderItemQuantity}
          handleQuantityClick={handleQuantityClick} 
          handleQuantityChangeCommit={handleQuantityChangeCommit}
          handleQuantityInputChange={handleQuantityInputChange}
          handleQuantityInputKeyDown={handleQuantityInputKeyDown}
          handlePrimarySaveAction={handlePrimarySaveAction}
          onCharge={handleChargeClick} 
          onOpenTickets={handleOpenTicketsClick}
          onSaveTicket={handleSaveTicketClick} 
          printers={printers}
          onClearTicket={handleClearTicket}
          onPrintRequest={handlePrintRequest}
        />
      </div>

      <SaveTicketModal isOpen={isSaveModalOpen} onClose={() => { setIsSaveModalOpen(false); setPendingPrintAction(false); }} onSave={handleSaveTicketComplete} editingTicket={editingTicket} />
      <OpenTicketsModal 
        isOpen={isOpenTicketsModalOpen} 
        tickets={savedTickets} 
        onClose={() => setIsOpenTicketsModalOpen(false)} 
        onLoadTicket={handleLoadTicket} 
        onDeleteTicket={(id) => removeTicket(id)} 
      />
      <SelectItemModal isOpen={isSelectItemModalOpen} onClose={() => setIsSelectItemModalOpen(false)} onSelect={handleSelectItem} allItems={items} />
      <ManageGridsModal isOpen={isManageGridsModalOpen} onClose={() => setIsManageGridsModalOpen(false)} initialGrids={customGrids} onSave={handleSaveGrids} />
      <AddGridModal isOpen={isAddGridModalOpen} onClose={() => setIsAddGridModalOpen(false)} onSave={handleSaveNewGrid} />

      <PriceInputModal 
        isOpen={!!variablePriceItem}
        onClose={() => setVariablePriceItem(null)}
        onConfirm={handleVariablePriceConfirm}
        item={variablePriceItem}
      />

      <ConfirmModal
        isOpen={confirmModalState.isOpen}
        onClose={() => setConfirmModalState(prev => ({ ...prev, isOpen: false }))}
        onConfirm={() => {
            confirmModalState.onConfirm();
            setConfirmModalState(prev => ({ ...prev, isOpen: false }));
        }}
        title={confirmModalState.title}
        confirmText={confirmModalState.confirmText}
        confirmButtonClass={confirmModalState.confirmButtonClass}
      >
        {confirmModalState.message}
      </ConfirmModal>
    </div>
  );
};

export default SalesScreen;

import React, { useState } from 'react';
import type { OrderItem, SavedTicket } from '../../types';
import { useAppContext } from '../../context/AppContext';
import { CheckIcon, TrashIcon, SalesIcon, CloseIcon, ArrowLeftIcon } from '../../constants';
import { Haptics, ImpactStyle } from '@capacitor/haptics';

interface OpenTicketsModalProps {
    isOpen: boolean;
    tickets: SavedTicket[];
    onClose: () => void;
    onLoadTicket: (ticket: SavedTicket) => void;
    onDeleteTicket: (id: string) => void;
}

const OpenTicketsModal: React.FC<OpenTicketsModalProps> = ({ isOpen, tickets, onClose, onLoadTicket, onDeleteTicket }) => {
    const { settings, mergeTickets } = useAppContext();
    const [isSelectionMode, setIsSelectionMode] = useState(false);
    const [selectedTicketIds, setSelectedTicketIds] = useState<Set<string>>(new Set());
    const [deletingTicketId, setDeletingTicketId] = useState<string | null>(null);

    const calculateTotal = (items: OrderItem[]) => {
        const subtotal = items.reduce((sum, item) => sum + item.price * item.quantity, 0);
        const taxMultiplier = settings.taxEnabled ? (1 + settings.taxRate / 100) : 1;
        return subtotal * taxMultiplier;
    };

    const toggleSelection = async (id: string) => {
        await Haptics.impact({ style: ImpactStyle.Light });
        const newSet = new Set(selectedTicketIds);
        if (newSet.has(id)) {
            newSet.delete(id);
        } else {
            newSet.add(id);
        }
        setSelectedTicketIds(newSet);
    };

    const handleMerge = async () => {
        if (selectedTicketIds.size < 2) return;

        const ids = Array.from(selectedTicketIds) as string[];
        const firstTicket = tickets.find(t => t.id === ids[0]);
        const defaultName = firstTicket ? `${firstTicket.name} + ${ids.length - 1}` : 'Merged Ticket';

        const newName = prompt("Enter a name for the merged ticket:", defaultName);
        if (newName) {
            await Haptics.impact({ style: ImpactStyle.Medium });
            mergeTickets(ids, newName);
            setIsSelectionMode(false);
            setSelectedTicketIds(new Set());
        }
    };

    const toggleMode = async () => {
        await Haptics.impact({ style: ImpactStyle.Light });
        setIsSelectionMode(!isSelectionMode);
        setSelectedTicketIds(new Set());
        setDeletingTicketId(null);
    };

    const handleLoad = async (ticket: SavedTicket) => {
        if (deletingTicketId) return;
        await Haptics.impact({ style: ImpactStyle.Medium });
        onLoadTicket(ticket);
    };

    const requestDelete = async (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        await Haptics.impact({ style: ImpactStyle.Medium });
        setDeletingTicketId(id);
    };

    const confirmDelete = async (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        await Haptics.notification({ type: ImpactStyle.Heavy });
        onDeleteTicket(id);
        setDeletingTicketId(null);
    };

    const cancelDelete = (e: React.MouseEvent) => {
        e.stopPropagation();
        setDeletingTicketId(null);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md flex items-center justify-center z-[100] p-4" onClick={onClose}>
          <div className="bg-surface rounded-3xl shadow-2xl w-full max-w-2xl flex flex-col overflow-hidden animate-fadeIn border border-white/10" style={{maxHeight: '85vh'}} onClick={e => e.stopPropagation()}>

            {/* Header */}
            <div className="flex-shrink-0 flex justify-between items-center px-8 py-6 border-b border-border bg-surface/50">
              <div>
                <h2 className="text-2xl font-black text-text-primary tracking-tight">
                    {isSelectionMode ? `Select Tickets` : 'Open Tickets'}
                </h2>
                <div className="flex items-center gap-2 mt-1">
                    <span className="w-2 h-2 rounded-full bg-primary animate-pulse"></span>
                    <p className="text-xs text-text-muted font-bold uppercase tracking-widest">
                        {tickets.length} Active {tickets.length === 1 ? 'Order' : 'Orders'}
                    </p>
                </div>
              </div>

              <div className="flex items-center gap-3">
                 {tickets.length > 1 && (
                     <button 
                        onClick={toggleMode} 
                        className={`px-5 py-2.5 text-xs font-black rounded-2xl uppercase tracking-widest transition-all ${isSelectionMode ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/20' : 'bg-surface-muted text-text-secondary hover:text-primary hover:bg-primary/10'}`}
                     >
                         {isSelectionMode ? 'Cancel' : 'Merge'}
                     </button>
                 )}
                 <button onClick={onClose} className="p-3 text-text-muted hover:text-text-primary bg-surface-muted rounded-2xl transition-all active:scale-90" aria-label="Close">
                    <CloseIcon className="h-5 w-5" />
                 </button>
              </div>
            </div>

            {/* List Body */}
            <div className="flex-grow overflow-y-auto px-6 py-6 bg-background/20 space-y-4">
              {tickets.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-center opacity-40">
                    <div className="bg-surface-muted p-8 rounded-full mb-6">
                        <SalesIcon className="h-16 w-16 text-text-muted" />
                    </div>
                    <p className="text-xl font-black text-text-primary uppercase tracking-tighter">No Active Tickets</p>
                    <p className="text-sm text-text-muted mt-2 max-w-[240px]">All cleared! New orders you save will appear here for management.</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 gap-3">
                  {tickets.map(ticket => {
                    const isSelected = selectedTicketIds.has(ticket.id);
                    const isDeleting = deletingTicketId === ticket.id;
                    const total = calculateTotal(ticket.items);

                    return (
                        <div 
                            key={ticket.id} 
                            onClick={() => isSelectionMode ? toggleSelection(ticket.id) : handleLoad(ticket)}
                            className={`group relative overflow-hidden rounded-2xl transition-all duration-300 border-2 active:bg-surface-muted ${
                                isSelectionMode 
                                    ? (isSelected ? 'bg-primary/10 border-primary shadow-xl shadow-primary/10' : 'bg-surface border-border hover:border-text-muted/30 opacity-60 grayscale-[0.5]')
                                    : (isDeleting ? 'bg-red-50 border-red-500 dark:bg-red-900/10 shadow-none' : 'bg-surface border-border hover:border-primary/40 hover:shadow-xl')
                            } cursor-pointer`}
                        >
                          <div className="p-5 flex items-center justify-between min-h-[90px]">
                              <div className="flex items-center gap-4 min-w-0">
                                  {isSelectionMode && (
                                      <div className={`h-7 w-7 rounded-full border-2 flex items-center justify-center transition-all duration-300 ${isSelected ? 'bg-primary border-primary text-white scale-110' : 'border-border bg-background'}`}>
                                          {isSelected && <CheckIcon className="h-4 w-4 stroke-[4px]" />}
                                      </div>
                                  )}

                                  <div className="min-w-0">
                                    <div className="flex items-center gap-2 mb-1.5">
                                        <p className="font-black text-text-primary text-xl truncate leading-none tracking-tight">{ticket.name}</p>
                                        <span className="flex-shrink-0 px-2.5 py-1 bg-surface-muted text-text-secondary text-[10px] font-black uppercase rounded-lg tracking-widest border border-border/50">
                                            {ticket.items.length} {ticket.items.length === 1 ? 'Item' : 'Items'}
                                        </span>
                                    </div>

                                    <div className="flex items-center gap-3">
                                        <p className="text-primary font-mono font-black text-base">₹{total.toFixed(2)}</p>
                                        {ticket.lastModified && (
                                            <span className="text-[11px] text-text-muted font-bold flex items-center gap-1 uppercase tracking-tighter opacity-60">
                                                <span className="w-1 h-1 bg-text-muted rounded-full"></span>
                                                {new Date(ticket.lastModified).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                            </span>
                                        )}
                                    </div>
                                  </div>
                              </div>

                              {!isSelectionMode && !isDeleting && (
                                  <div className="flex items-center gap-2">
                                    <button 
                                        onClick={(e) => requestDelete(e, ticket.id)} 
                                        className="p-3 text-text-muted hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30 rounded-2xl transition-all active:scale-90" 
                                        aria-label="Delete ticket"
                                    >
                                        <TrashIcon className="h-6 w-6" />
                                    </button>
                                    <div className="ml-2 px-6 py-3 bg-primary text-primary-content text-xs font-black uppercase tracking-[0.15em] rounded-2xl shadow-lg shadow-primary/30 group-hover:bg-primary-hover transition-all">
                                        Load
                                    </div>
                                  </div>
                              )}
                          </div>

                          {/* Inline Delete Confirmation Overlay */}
                          {isDeleting && (
                              <div className="absolute inset-0 bg-red-600 flex items-center justify-between px-6 animate-fadeIn z-10">
                                  <div className="flex items-center gap-3 text-white">
                                      <TrashIcon className="h-6 w-6 animate-bounce" />
                                      <span className="font-black text-sm uppercase tracking-widest">Delete this ticket?</span>
                                  </div>
                                  <div className="flex gap-2">
                                      <button 
                                          onClick={cancelDelete} 
                                          className="px-4 py-2 bg-white/20 hover:bg-white/30 text-white rounded-xl text-xs font-black uppercase transition-all"
                                      >
                                          Cancel
                                      </button>
                                      <button 
                                          onClick={(e) => confirmDelete(e, ticket.id)} 
                                          className="px-6 py-2 bg-white text-red-600 rounded-xl text-xs font-black uppercase shadow-xl hover:bg-gray-100 transition-all active:scale-95"
                                      >
                                          Confirm
                                      </button>
                                  </div>
                              </div>
                          )}
                        </div>
                    );
                  })}
                </div>
              )}
            </div>

            {/* Footer */}
            <div className="flex-shrink-0 flex items-center justify-between px-8 py-8 border-t border-border bg-surface">
                 <div className="flex-1">
                    {isSelectionMode && selectedTicketIds.size > 0 && (
                        <p className="text-sm font-black text-primary uppercase tracking-widest animate-fadeIn">
                             {selectedTicketIds.size} {selectedTicketIds.size === 1 ? 'ticket' : 'tickets'} selected
                        </p>
                    )}
                 </div>
                 <div className="flex gap-4">
                    {isSelectionMode && (
                        <button 
                            onClick={handleMerge} 
                            disabled={selectedTicketIds.size < 2}
                            className="px-8 py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-emerald-700 disabled:opacity-30 disabled:grayscale transition-all shadow-xl shadow-emerald-600/30 flex items-center gap-3"
                        >
                            <SalesIcon className="h-5 w-5" />
                            Merge
                        </button>
                    )}
                    <button 
                        onClick={onClose} 
                        className="px-10 py-4 bg-surface-muted text-text-secondary rounded-2xl font-black uppercase tracking-[0.2em] text-xs hover:bg-gray-200 dark:hover:bg-gray-700 transition-all border border-border/50"
                    >
                        Close
                    </button>
                 </div>
            </div>
          </div>
        </div>
      );
}

export default OpenTicketsModal;

import React from 'react';
