import SettingsScreen from '../screens/SettingsScreen';
import ReportsScreen from '../screens/ReportsScreen';
import AboutScreen from '../screens/AboutScreen';

const SCREEN_TIMEOUT = 10 * 60 * 1000; // 10 Minutes

// Optimized KeepAlive component
const KeepAliveScreen = React.memo(({ isVisible, children }: { isVisible: boolean, children: React.ReactNode }) => {
    return (
        <div 
            className={`flex flex-col h-full w-full absolute inset-0 bg-background transition-opacity duration-200 ${isVisible ? 'opacity-100 z-10' : 'opacity-0 z-[-1] pointer-events-none'}`}
            style={{ visibility: isVisible ? 'visible' : 'hidden' }}
        >
            {children}
        </div>
    );
});

const Layout: React.FC = () => {
  const { isDrawerOpen, openDrawer, isAddPrinterModalOpen, closeAddPrinterModal, addPrinter } = useAppContext();
  const location = useLocation();
  const { pathname } = location;

  // --- GESTURE LOGIC ---
  const swipeHandlers = useEdgeSwipe({
      onSwipe: () => !isDrawerOpen && openDrawer(),
      threshold: 50,
      edgeWidth: 32 // 32px hit zone from the left
  });

  // --- SCREEN MANAGEMENT ---
  const [activeScreens, setActiveScreens] = useState<Record<string, number>>({ '/sales': Date.now() });

  useEffect(() => {
      setActiveScreens(prev => ({ ...prev, [pathname]: Date.now() }));
  }, [pathname]);

  // Garbage collection for inactive screens
  useEffect(() => {
      const interval = setInterval(() => {
          const now = Date.now();
          setActiveScreens(prev => {
              const next = { ...prev };
              let changed = false;
              Object.keys(next).forEach(path => {
                  // Keep Sales screen always alive
                  if (path !== '/sales' && path !== pathname && now - next[path] > SCREEN_TIMEOUT) {
                      delete next[path];
                      changed = true;
                  }
              });
              return changed ? next : prev;
          });
      }, 60000);
      return () => clearInterval(interval);
  }, [pathname]);

  const displayTitle = useMemo(() => {
      const currentLink = NAV_LINKS.find(link => pathname.startsWith(link.path));
      return currentLink ? currentLink.label : 'Restaurant POS';
  }, [pathname]);

  const showDefaultHeader = !['/sales', '/receipts', '/settings', '/items', '/reports', '/about'].includes(pathname); 

  if (!['/sales', '/receipts', '/items', '/settings', '/reports', '/about'].some(p => pathname.startsWith(p))) {
      return <Navigate to="/sales" replace />;
  }

  return (
    <div className="relative h-screen w-full overflow-hidden bg-background text-text-primary flex flex-col">
      <OfflineManager />

      {/* SWIPE CATCHER LAYER */}
      {!isDrawerOpen && (
        <div 
            className="fixed left-0 top-0 bottom-0 w-8 z-[100] touch-none" 
            {...swipeHandlers}
        />
      )}

      {showDefaultHeader && <Header title={displayTitle} onMenuClick={openDrawer} />}
      <NavDrawer />

      <main className="flex-1 relative overflow-hidden">
        <KeepAliveScreen isVisible={pathname === '/sales'}><SalesScreen /></KeepAliveScreen>
        {activeScreens['/receipts'] && <KeepAliveScreen isVisible={pathname === '/receipts'}><ReceiptsScreen /></KeepAliveScreen>}
        {activeScreens['/reports'] && <KeepAliveScreen isVisible={pathname === '/reports'}><ReportsScreen /></KeepAliveScreen>}
        {activeScreens['/items'] && <KeepAliveScreen isVisible={pathname === '/items'}><ItemsScreen /></KeepAliveScreen>}
        {activeScreens['/settings'] && <KeepAliveScreen isVisible={pathname === '/settings'}><SettingsScreen /></KeepAliveScreen>}
        {activeScreens['/about'] && <KeepAliveScreen isVisible={pathname === '/about'}><AboutScreen /></KeepAliveScreen>}
      </main>

      <AddPrinterModal 
        isOpen={isAddPrinterModalOpen} 
        onClose={closeAddPrinterModal} 
        onSave={(p) => {
            addPrinter(p);
            closeAddPrinterModal();
        }} 
      />
    </div>
  );
};

export default Layout;

import React, { createContext, useState, useContext, ReactNode, useCallback, useEffect, useMemo } from 'react';
import { 
    Printer, Receipt, Item, AppSettings, SavedTicket, 
    CustomGrid, PaymentType, OrderItem, AppContextType, Table, Theme
} from '../types';
import { Capacitor } from '@capacitor/core';
import { Filesystem, Directory, Encoding } from '@capacitor/filesystem';
import { Share } from '@capacitor/share';
import { StatusBar, Style } from '@capacitor/status-bar';
import { exportItemsToCsv } from '../utils/csvHelper';
import { requestAppPermissions } from '../utils/permissions';
import { requestNotificationPermission, sendLowStockAlert } from '../utils/notificationHelper';
import { db, signOutUser, auth } from '../firebase';
import { collection, onSnapshot, doc, setDoc, deleteDoc, writeBatch, Timestamp, query, orderBy, limit, getDocs, getDoc, increment } from 'firebase/firestore';
import { onAuthStateChanged, User } from 'firebase/auth';
import { idb } from '../utils/indexedDB'; 

const DEFAULT_SETTINGS: AppSettings = { 
    taxEnabled: true, 
    taxRate: 5, 
    storeName: 'My Restaurant',
    storeAddress: '123 Food Street, Flavor Town',
    receiptFooter: 'Follow us @myrestaurant',
    reportsPIN: '',
    shiftMorningStart: '06:00',
    shiftMorningEnd: '17:30',
    shiftNightEnd: '05:00',
    notificationsEnabled: false,
    notifyLowStock: false,
    lowStockThreshold: 10,
    notifyDailySummary: false,
    dailySummaryTime: '22:00'
};

const AppContext = createContext<AppContextType | undefined>(undefined);

const SETTINGS_CACHE_KEY = 'pos_settings_cache';
const PRINTERS_CACHE_KEY = 'pos_local_printers';
const ONBOARDING_COMPLETED_KEY = 'pos_onboarding_completed_v1';
const ACTIVE_GRID_KEY = 'pos_active_grid_id';

const safeStorage = {
    getItem: (key: string) => { try { return localStorage.getItem(key); } catch(e) { return null; } },
    setItem: (key: string, val: string) => { try { localStorage.setItem(key, val); } catch(e) {} }
};

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [showOnboarding, setShowOnboarding] = useState(() => !safeStorage.getItem(ONBOARDING_COMPLETED_KEY));
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [headerTitle, setHeaderTitle] = useState('');
  const [isReportsUnlocked, setReportsUnlocked] = useState(false);
  const [theme, setThemeState] = useState<Theme>(() => (safeStorage.getItem('theme') as Theme) || 'system');
  const [isAddPrinterModalOpen, setIsAddPrinterModalOpen] = useState(false);

  const openAddPrinterModal = useCallback(() => setIsAddPrinterModalOpen(true), []);
  const closeAddPrinterModal = useCallback(() => setIsAddPrinterModalOpen(false), []);

  const setTheme = useCallback((newTheme: Theme) => {
    setThemeState(newTheme);
    safeStorage.setItem('theme', newTheme);
  }, []);

  // --- ROBUST THEME & STATUS BAR LOGIC ---
  const applyTheme = useCallback(async () => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const isDark = theme === 'system' ? mediaQuery.matches : theme === 'dark';

    // 1. CSS
    document.documentElement.classList.toggle('dark', isDark);

    // 2. Native Status Bar
    if (Capacitor.isNativePlatform()) {
        try {
            if (Capacitor.getPlatform() === 'android') {
                await StatusBar.setOverlaysWebView({ overlay: false });
            }

            const style = isDark ? Style.Dark : Style.Light;
            await StatusBar.setStyle({ style });

            if (Capacitor.getPlatform() === 'android') {
                const color = isDark ? '#121212' : '#FFFFFF';
                // Small delay to ensure style applies before color on some Android versions
                setTimeout(() => StatusBar.setBackgroundColor({ color }), 50);
            }
        } catch (e) {
            console.warn('StatusBar error:', e);
        }
    }
  }, [theme]);

  // Initial and Listener-based Theme Application
  useEffect(() => {
    applyTheme();

    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleSystemChange = () => {
        if (theme === 'system') applyTheme();
    };

    // Also listen for visibility change (user comes back from Settings app)
    const handleVisibilityChange = () => {
        if (document.visibilityState === 'visible') applyTheme();
    };

    mediaQuery.addEventListener('change', handleSystemChange);
    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
        mediaQuery.removeEventListener('change', handleSystemChange);
        document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [applyTheme, theme]);

  const openDrawer = useCallback(() => setIsDrawerOpen(true), []);
  const closeDrawer = useCallback(() => setIsDrawerOpen(false), []);
  const toggleDrawer = useCallback(() => setIsDrawerOpen(prev => !prev), []);

  // Data State
  const [settings, setSettingsState] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [items, setItemsState] = useState<Item[]>([]);
  const [customGrids, setCustomGridsState] = useState<CustomGrid[]>([]);
  const [receipts, setReceiptsState] = useState<Receipt[]>([]);
  const [printers, setPrintersState] = useState<Printer[]>(() => {
      const cached = safeStorage.getItem(PRINTERS_CACHE_KEY);
      return cached ? JSON.parse(cached) : [];
  });
  const [paymentTypes, setPaymentTypesState] = useState<PaymentType[]>([]);
  const [savedTickets, setSavedTicketsState] = useState<SavedTicket[]>([]);
  const [tables, setTablesState] = useState<Table[]>([]);
  const [activeGridId, setActiveGridIdState] = useState<string>(() => safeStorage.getItem(ACTIVE_GRID_KEY) || 'All');

  const setActiveGridId = useCallback((id: string) => {
      setActiveGridIdState(id);
      safeStorage.setItem(ACTIVE_GRID_KEY, id);
  }, []);

  const [currentOrder, setCurrentOrder] = useState<OrderItem[]>([]);

  // CART ACTIONS - Optimized
  const addToOrder = useCallback((item: Item) => {
    setCurrentOrder(current => {
      // Check last item for consecutive add optimization
      const lastItem = current.length > 0 ? current[current.length - 1] : null;

      // If same item ID and Price, increment quantity
      if (lastItem && lastItem.id === item.id && lastItem.price === item.price) {
        const newOrder = [...current];
        newOrder[newOrder.length - 1] = { ...lastItem, quantity: lastItem.quantity + 1 };
        return newOrder;
      }
      // Else add new line item
      return [...current, { ...item, imageUrl: '', quantity: 1, lineItemId: `L${Date.now()}-${Math.random().toString(36).substr(2, 5)}` }];
    });
  }, []);

  const removeFromOrder = useCallback((lineItemId: string) => {
    setCurrentOrder(current => {
      const itemIndex = current.findIndex(i => i.lineItemId === lineItemId);
      if (itemIndex === -1) return current;

      const itemToUpdate = current[itemIndex];
      if (itemToUpdate.quantity > 1) {
        const newOrder = [...current];
        newOrder[itemIndex] = { ...itemToUpdate, quantity: itemToUpdate.quantity - 1 };
        return newOrder;
      }
      // Remove if quantity becomes 0
      return current.filter(i => i.lineItemId !== lineItemId);
    });
  }, []);

  const deleteLineItem = useCallback((lineItemId: string) => {
    setCurrentOrder(prev => prev.filter(i => i.lineItemId !== lineItemId));
  }, []);

  const updateOrderItemQuantity = useCallback((lineItemId: string, newQuantity: number) => {
    if (isNaN(newQuantity) || newQuantity <= 0) {
        deleteLineItem(lineItemId);
    } else {
        setCurrentOrder(prev => prev.map(i => i.lineItemId === lineItemId ? { ...i, quantity: newQuantity } : i));
    }
  }, [deleteLineItem]);

  const clearOrder = useCallback(() => setCurrentOrder([]), []);

  const loadOrder = useCallback((items: OrderItem[]) => {
      // Regenerate line IDs to prevent conflicts if loaded multiple times
      setCurrentOrder(items.map(item => ({ 
          ...item, 
          lineItemId: item.lineItemId || `L${Date.now()}-${Math.random().toString(36).substr(2, 5)}` 
      })));
  }, []);

  // --- INITIAL DATA LOAD ---
  useEffect(() => {
    const unsubAuth = onAuthStateChanged(auth, async (currentUser) => {
        if (currentUser) {
            setUser(currentUser);
            const uid = currentUser.uid;

            try {
                // Parallel fetching for performance
                const [settingsSnap, itemsSnap, ptSnap, tblSnap, tktSnap, grdSnap] = await Promise.all([
                    getDoc(doc(db, 'users', uid, 'config', 'settings')),
                    getDocs(collection(db, 'users', uid, 'items')),
                    getDocs(collection(db, 'users', uid, 'payment_types')),
                    getDocs(query(collection(db, 'users', uid, 'tables'), orderBy('order'))),
                    getDocs(collection(db, 'users', uid, 'saved_tickets')),
                    getDocs(query(collection(db, 'users', uid, 'custom_grids'), orderBy('order')))
                ]);

                if (settingsSnap.exists()) setSettingsState({ ...DEFAULT_SETTINGS, ...settingsSnap.data() as AppSettings });
                setItemsState(itemsSnap.docs.map(d => d.data() as Item));
                setPaymentTypesState(ptSnap.docs.map(d => d.data() as PaymentType));
                setTablesState(tblSnap.docs.map(d => d.data() as Table));
                setSavedTicketsState(tktSnap.docs.map(d => d.data() as SavedTicket));
                setCustomGridsState(grdSnap.docs.map(d => d.data() as CustomGrid));
            } catch (e) { 
                console.error("Initial load sync deferred or failed", e); 
            }

            // Real-time listener ONLY for recent receipts to save bandwidth
            const unsubReceipts = onSnapshot(
                query(collection(db, 'users', uid, 'receipts'), orderBy('date', 'desc'), limit(50)), 
                (snap) => {
                    setReceiptsState(snap.docs.map(d => ({ ...d.data(), date: (d.data().date as Timestamp).toDate() } as Receipt)));
                }
            );

            setIsLoading(false);
            return () => unsubReceipts();
        } else {
            setUser(null);
            setIsLoading(false);
        }
    });
    return () => unsubAuth();
  }, []);

  // --- DATA ACTIONS ---

  const addReceipt = useCallback(async (receipt: Receipt) => {
    if (!user) return;

    // Strip heavy image data before saving to DB
    const persistenceFriendlyReceipt = {
        ...receipt,
        items: receipt.items.map(item => {
            const { imageUrl, ...rest } = item;
            return { ...rest, imageUrl: '' };
        })
    };

    // Optimistic UI update
    setReceiptsState(prev => [receipt, ...prev].slice(0, 100));

    // Dual write: IndexedDB (local backup) + Firestore (cloud)
    idb.saveReceipt(persistenceFriendlyReceipt); 
    const batch = writeBatch(db);
    batch.set(doc(db, 'users', user.uid, 'receipts', receipt.id), persistenceFriendlyReceipt);

    // Stock Management
    const updatedItems = [...items];
    let stockChanged = false;

    receipt.items.forEach(orderItem => {
        const idx = updatedItems.findIndex(i => i.id === orderItem.id);
        if (idx > -1) {
            const oldStock = updatedItems[idx].stock;
            updatedItems[idx].stock = Math.max(0, oldStock - orderItem.quantity);
            stockChanged = true;

            batch.update(doc(db, 'users', user.uid, 'items', orderItem.id), { stock: increment(-orderItem.quantity) });

            if (settings.notifyLowStock && updatedItems[idx].stock <= (settings.lowStockThreshold || 0)) {
                sendLowStockAlert(updatedItems[idx].name, updatedItems[idx].stock);
            }
        }
    });

    if (stockChanged) setItemsState(updatedItems);

    try { await batch.commit(); } catch (e) { console.warn("Background sync deferred"); }
  }, [user, items, settings]);

  const saveTicket = useCallback(async (t: SavedTicket) => {
      if (!user) return;
      setSavedTicketsState(v => [...v.filter(x => x.id !== t.id), t]);
      await setDoc(doc(db, 'users', user.uid, 'saved_tickets', t.id), t);
  }, [user]);

  const removeTicket = useCallback(async (id: string) => {
      if (!user) return;
      setSavedTicketsState(v => v.filter(x => x.id !== id));
      await deleteDoc(doc(db, 'users', user.uid, 'saved_tickets', id));
  }, [user]);

  const mergeTickets = useCallback(async (ticketIds: string[], newName: string) => {
      if (!user) return;
      const ticketsToMerge = savedTickets.filter(t => ticketIds.includes(t.id));
      if (ticketsToMerge.length < 2) return;

      const allItems = ticketsToMerge.flatMap(t => t.items);
      const newTicket: SavedTicket = {
          id: `T${Date.now()}`,
          name: newName,
          items: allItems,
          lastModified: Date.now()
      };

      await saveTicket(newTicket);
      const batch = writeBatch(db);
      for (const id of ticketIds) {
          batch.delete(doc(db, 'users', user.uid, 'saved_tickets', id));
      }
      await batch.commit();

      setSavedTicketsState(prev => [...prev.filter(t => !ticketIds.includes(t.id)), newTicket]);
  }, [savedTickets, saveTicket, user]);

  const completeOnboarding = useCallback(async () => {
      if (Capacitor.isNativePlatform()) {
          const p = await requestAppPermissions();
          await requestNotificationPermission();
          if (!p) return false;
      }
      safeStorage.setItem(ONBOARDING_COMPLETED_KEY, 'true');
      setShowOnboarding(false);
      return true;
  }, []);

  const updateSettings = useCallback(async (s: Partial<AppSettings>) => {
      if (!user) return;
      const next = { ...settings, ...s };
      setSettingsState(next);
      safeStorage.setItem(SETTINGS_CACHE_KEY, JSON.stringify(next));
      await setDoc(doc(db, 'users', user.uid, 'config', 'settings'), next, { merge: true });
  }, [user, settings]);

  // Local-only Printer Management
  const addPrinter = useCallback((p: Printer) => {
      setPrintersState(v => {
          const next = [...v, p];
          safeStorage.setItem(PRINTERS_CACHE_KEY, JSON.stringify(next));
          return next;
      });
  }, []);

  const removePrinter = useCallback((id: string) => {
      setPrintersState(v => {
          const next = v.filter(p => p.id !== id);
          safeStorage.setItem(PRINTERS_CACHE_KEY, JSON.stringify(next));
          return next;
      });
  }, []);

  // Standard CRUD Actions
  const addPaymentType = useCallback(async (p: Omit<PaymentType, 'id' | 'enabled' | 'type'>) => {
      if (!user) return;
      const id = `pt_${Date.now()}`;
      const pt = { ...p, id, enabled: true, type: 'other' } as PaymentType;
      setPaymentTypesState(v => [...v, pt]);
      await setDoc(doc(db, 'users', user.uid, 'payment_types', id), pt);
  }, [user]);

  const updatePaymentType = useCallback(async (p: PaymentType) => {
      if (!user) return;
      setPaymentTypesState(v => v.map(i => i.id === p.id ? p : i));
      await setDoc(doc(db, 'users', user.uid, 'payment_types', p.id), p);
  }, [user]);

  const removePaymentType = useCallback(async (id: string) => {
      if (!user) return;
      setPaymentTypesState(v => v.filter(p => p.id !== id));
      await deleteDoc(doc(db, 'users', user.uid, 'payment_types', id));
  }, [user]);

  const deleteReceipt = useCallback(async (id: string) => {
      if (!user) return;
      setReceiptsState(v => v.filter(r => r.id !== id));
      await deleteDoc(doc(db, 'users', user.uid, 'receipts', id));
  }, [user]);

  const addItem = useCallback(async (i: Item) => {
      if (!user) return;
      setItemsState(v => [...v, i]);
      await setDoc(doc(db, 'users', user.uid, 'items', i.id), i);
  }, [user]);

  const updateItem = useCallback(async (i: Item) => {
      if (!user) return;
      setItemsState(v => v.map(x => x.id === i.id ? i : x));
      await setDoc(doc(db, 'users', user.uid, 'items', i.id), i);
  }, [user]);

  const deleteItem = useCallback(async (id: string) => {
      if (!user) return;
      setItemsState(v => v.filter(x => x.id !== id));
      await deleteDoc(doc(db, 'users', user.uid, 'items', id));
  }, [user]);

  const addCustomGrid = useCallback(async (g: CustomGrid) => {
      if (!user) return;
      setCustomGridsState(v => [...v, g]);
      await setDoc(doc(db, 'users', user.uid, 'custom_grids', g.id), g);
  }, [user]);

  const updateCustomGrid = useCallback(async (g: CustomGrid) => {
      if (!user) return;
      setCustomGridsState(v => v.map(x => x.id === g.id ? g : x));
      await setDoc(doc(db, 'users', user.uid, 'custom_grids', g.id), g);
  }, [user]);

  const deleteCustomGrid = useCallback(async (id: string) => {
      if (!user) return;
      setCustomGridsState(v => v.filter(x => x.id !== id));
      await deleteDoc(doc(db, 'users', user.uid, 'custom_grids', id));
  }, [user]);

  const setCustomGrids = useCallback(async (gs: CustomGrid[]) => {
      if (!user) return;
      setCustomGridsState(gs);
      const batch = writeBatch(db);
      gs.forEach(g => batch.set(doc(db, 'users', user.uid, 'custom_grids', g.id), g));
      await batch.commit();
  }, [user]);

  const addTable = useCallback(async (n: string) => {
      if (!user) return;
      const t = { id: `tbl_${Date.now()}`, name: n, order: tables.length };
      setTablesState(v => [...v, t]);
      await setDoc(doc(db, 'users', user.uid, 'tables', t.id), t);
  }, [user, tables.length]);

  const updateTable = useCallback(async (t: Table) => {
      if (!user) return;
      setTablesState(v => v.map(x => x.id === t.id ? t : x));
      await setDoc(doc(db, 'users', user.uid, 'tables', t.id), t);
  }, [user]);

  const removeTable = useCallback(async (id: string) => {
      if (!user) return;
      setTablesState(v => v.filter(x => x.id !== id));
      await deleteDoc(doc(db, 'users', user.uid, 'tables', id));
  }, [user]);

  const setTables = useCallback(async (ts: Table[]) => {
      if (!user) return;
      setTablesState(ts);
      const batch = writeBatch(db);
      ts.forEach(t => batch.set(doc(db, 'users', user.uid, 'tables', t.id), t));
      await batch.commit();
  }, [user]);

  const exportItemsCsv = useCallback(async () => {
      const csvString = exportItemsToCsv(items);
      const fileName = `inventory_export_${new Date().toISOString().slice(0, 10)}.csv`;
      try {
          if (Capacitor.isNativePlatform()) {
              const result = await Filesystem.writeFile({ path: fileName, data: csvString, directory: Directory.Documents, encoding: Encoding.UTF8 });
              await Share.share({ url: result.uri, title: 'Export Inventory' });
          } else {
              const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
              const link = document.createElement("a");
              link.setAttribute("href", URL.createObjectURL(blob));
              link.setAttribute("download", fileName);
              document.body.appendChild(link);
              link.click();
              document.body.removeChild(link);
          }
      } catch (error) { console.error("Export failed", error); }
  }, [items]);

  const replaceItems = useCallback((is: Item[]) => {
      if (!user) return;
      setItemsState(is);
      const batch = writeBatch(db);
      is.forEach(i => batch.set(doc(db, 'users', user.uid, 'items', i.id), i));
      batch.commit();
  }, [user]);

  // Context Value Construction
  const value = useMemo(() => ({
      user, signOut: signOutUser,
      isDrawerOpen, openDrawer, closeDrawer, toggleDrawer, 
      headerTitle, setHeaderTitle, theme, setTheme,
      showOnboarding, completeOnboarding, isLoading, 
      isAddPrinterModalOpen, openAddPrinterModal, closeAddPrinterModal,
      settings, updateSettings,
      printers, addPrinter, removePrinter,
      paymentTypes, addPaymentType, updatePaymentType, removePaymentType,
      receipts, addReceipt, loadMoreReceipts: async () => {}, hasMoreReceipts: false, deleteReceipt,
      items, addItem, updateItem, deleteItem,
      savedTickets, saveTicket, removeTicket, mergeTickets,
      customGrids, addCustomGrid, updateCustomGrid, deleteCustomGrid, setCustomGrids,
      tables, addTable, updateTable, removeTable, setTables,
      activeGridId, setActiveGridId,
      currentOrder, addToOrder, removeFromOrder, deleteLineItem, updateOrderItemQuantity, clearOrder, loadOrder,
      exportData: () => {}, restoreData: () => {}, 
      exportItemsCsv, replaceItems,
      isReportsUnlocked, setReportsUnlocked
  }), [
      user, isDrawerOpen, headerTitle, theme, showOnboarding, isLoading, isAddPrinterModalOpen, settings, items, customGrids, receipts, 
      printers, paymentTypes, savedTickets, tables, activeGridId, currentOrder, isReportsUnlocked,
      openDrawer, closeDrawer, toggleDrawer, setTheme, completeOnboarding, openAddPrinterModal, closeAddPrinterModal,
      updateSettings, addPrinter, removePrinter,
      addPaymentType, updatePaymentType, removePaymentType, addReceipt, deleteReceipt, addItem, updateItem, deleteItem,
      saveTicket, removeTicket, mergeTickets, addCustomGrid, updateCustomGrid, deleteCustomGrid, setCustomGrids,
      addTable, updateTable, removeTable, setTables, setActiveGridId, addToOrder, removeFromOrder, deleteLineItem,
      updateOrderItemQuantity, clearOrder, loadOrder, exportItemsCsv, replaceItems
  ]);

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

export const useAppContext = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useAppContext must be used within an AppProvider');
  return context;
};

import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import type { OrderItem, SavedTicket, Item, CustomGrid, SplitPaymentDetail, Receipt } from '../types';
import { useAppContext } from '../context/AppContext';
import { useDebounce } from '../hooks/useDebounce';
import { printBill } from '../utils/printerHelper';

// Modals and Child Components
import SaveTicketModal from '../components/modals/SaveTicketModal';
import OpenTicketsModal from '../components/modals/OpenTicketsModal';
import ManageGridsModal from '../components/modals/ManageGridsModal';
import SelectItemModal from '../components/modals/SelectItemModal';
import AddGridModal from '../components/modals/AddGridModal';
import ConfirmModal from '../components/modals/ConfirmModal';
import PriceInputModal from '../components/modals/PriceInputModal';
import SalesHeader from '../components/sales/SalesHeader';
import ItemGrid from '../components/sales/ItemGrid';
import CategoryTabs from '../components/sales/CategoryTabs';
import Ticket from '../components/sales/Ticket';
import ChargeScreen from '../components/sales/ChargeScreen';
import { ItemsIcon, SalesIcon } from '../constants';

type SalesView = 'grid' | 'payment';

const generateId = () => crypto.randomUUID ? crypto.randomUUID() : `G${Date.now()}`;

// --- SEARCH WORKER CODE ---
const SEARCH_WORKER_CODE = `
self.onmessage = function(e) {
    const { items, query } = e.data;
    if (!query || !query.trim()) {
        self.postMessage([]);
        return;
    }
    const lowerQuery = query.trim().toLowerCase();
    const results = items.filter(item => {
        const nameMatch = item.name.toLowerCase().includes(lowerQuery);
        const categoryMatch = item.category ? item.category.toLowerCase().includes(lowerQuery) : false;
        return nameMatch || categoryMatch;
    });
    self.postMessage(results);
};
`;

const SalesScreen: React.FC = () => {
  const { 
      openDrawer, settings, printers, addReceipt, openAddPrinterModal,
      items, customGrids, addCustomGrid, updateCustomGrid, setCustomGrids,
      savedTickets, saveTicket, removeTicket,
      currentOrder, addToOrder, removeFromOrder, deleteLineItem, 
      updateOrderItemQuantity, clearOrder, loadOrder,
      activeGridId, setActiveGridId
  } = useAppContext();

  const navigate = useNavigate();
  const location = useLocation();
  const isActive = location.pathname === '/sales';

  // --- 1. DYNAMIC GRID SIZING ---
  const getGridSize = () => {
      // 25 items for desktop/tablet landscape, 20 for mobile
      return window.innerWidth >= 768 ? 25 : 20;
  };
  const [gridSize, setGridSize] = useState(getGridSize());

  useEffect(() => {
      let timeoutId: any;
      const handleResize = () => {
          clearTimeout(timeoutId);
          timeoutId = setTimeout(() => {
              setGridSize(getGridSize());
          }, 150); // Debounce resize event
      };
      window.addEventListener('resize', handleResize);
      return () => {
          window.removeEventListener('resize', handleResize);
          clearTimeout(timeoutId);
      };
  }, []);

  // Main View State
  const [salesView, setSalesView] = useState<SalesView>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const debouncedSearchQuery = useDebounce(searchQuery, 300);

  // Search Worker
  const [workerSearchResults, setWorkerSearchResults] = useState<Item[]>([]);
  const searchWorkerRef = useRef<Worker | null>(null);

  // Ticket Management
  const [editingTicket, setEditingTicket] = useState<SavedTicket | null>(null);
  const [editingQuantityItemId, setEditingQuantityItemId] = useState<string | null>(null);
  const [tempQuantity, setTempQuantity] = useState<string>('');

  // UI State
  const [pendingPrintAction, setPendingPrintAction] = useState(false);
  const [isGridEditing, setIsGridEditing] = useState(false);
  const [paymentResult, setPaymentResult] = useState<{ method: string, change: number, receiptId: string, date: Date } | null>(null);

  // Pagination
  const [displayLimit, setDisplayLimit] = useState(40);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const loadMoreRef = useRef<HTMLDivElement>(null);

  // Modals
  const [isManageGridsModalOpen, setIsManageGridsModalOpen] = useState(false);
  const [isSaveModalOpen, setIsSaveModalOpen] = useState(false);
  const [isOpenTicketsModalOpen, setIsOpenTicketsModalOpen] = useState(false);
  const [isSelectItemModalOpen, setIsSelectItemModalOpen] = useState(false);
  const [isAddGridModalOpen, setIsAddGridModalOpen] = useState(false);
  const [assigningSlot, setAssigningSlot] = useState<{gridId: string, slotIndex: number} | null>(null);
  const [variablePriceItem, setVariablePriceItem] = useState<Item | null>(null);

  const [confirmModalState, setConfirmModalState] = useState<{
      isOpen: boolean; title: string; message: React.ReactNode; onConfirm: () => void;
      confirmText?: string; confirmButtonClass?: string;
  }>({ isOpen: false, title: '', message: '', onConfirm: () => {} });

  const [isTicketVisible, setIsTicketVisible] = useState(false);

  // Worker Lifecycle
  useEffect(() => {
      const blob = new Blob([SEARCH_WORKER_CODE], { type: 'application/javascript' });
      const worker = new Worker(URL.createObjectURL(blob));
      searchWorkerRef.current = worker;
      worker.onmessage = (e) => setWorkerSearchResults(e.data);
      return () => worker.terminate();
  }, []);

  // Dispatch Search
  useEffect(() => {
      if (searchWorkerRef.current && debouncedSearchQuery.trim()) {
          searchWorkerRef.current.postMessage({ items: items, query: debouncedSearchQuery });
      } else {
          setWorkerSearchResults([]);
      }
  }, [debouncedSearchQuery, items]);

  // Reset View on Activation/Category Change
  useEffect(() => {
    if (isActive && scrollContainerRef.current) scrollContainerRef.current.scrollTop = 0;
  }, [isActive]);

  useEffect(() => {
    setDisplayLimit(40);
    setIsGridEditing(false);
    if (scrollContainerRef.current) scrollContainerRef.current.scrollTop = 0;
  }, [activeGridId, debouncedSearchQuery]);

  // --- LOGIC HANDLERS ---

  const handleItemClick = useCallback((item: Item) => {
      if (item.price === 0) setVariablePriceItem(item);
      else addToOrder(item);
  }, [addToOrder]);

  const handleVariablePriceConfirm = (price: number) => {
      if (variablePriceItem) {
          addToOrder({ ...variablePriceItem, price: price });
          setVariablePriceItem(null);
      }
  };

  const handleQuantityClick = useCallback((item: OrderItem) => {
    setEditingQuantityItemId(item.lineItemId);
    setTempQuantity(item.quantity.toString());
  }, []);

  const handleQuantityChangeCommit = useCallback(() => {
    if (!editingQuantityItemId) return;
    const newQuantity = parseInt(tempQuantity, 10);
    updateOrderItemQuantity(editingQuantityItemId, newQuantity);
    setEditingQuantityItemId(null);
  }, [editingQuantityItemId, tempQuantity, updateOrderItemQuantity]);

  const handleProcessPayment = useCallback((method: string, tendered: number, splitDetails?: SplitPaymentDetail[]) => {
    if (editingTicket) removeTicket(editingTicket.id);
    const receiptId = `R${Date.now()}`;
    const receiptDate = new Date();

    const subtotal = currentOrder.reduce((sum, item) => sum + item.price * item.quantity, 0);
    const tax = settings.taxEnabled ? subtotal * (settings.taxRate / 100) : 0;
    const total = subtotal + tax;

    const newReceipt: Receipt = { 
        id: receiptId, 
        date: receiptDate, 
        items: currentOrder.map(item => ({...item, imageUrl: ''})), 
        total, 
        paymentMethod: method 
    };

    if (splitDetails && splitDetails.length > 0) newReceipt.splitDetails = splitDetails;

    addReceipt(newReceipt);
    setPaymentResult({ method, change: tendered - total, receiptId, date: receiptDate });
  }, [addReceipt, currentOrder, editingTicket, removeTicket, settings]);

  // --- GRID LOGIC ---
  const itemsForDisplay = useMemo<(Item | null)[]>(() => {
    if (debouncedSearchQuery.trim()) return workerSearchResults;
    if (activeGridId === 'All') return items;

    const grid = customGrids.find(g => g.id === activeGridId);
    if (grid) {
        const sourceIds = Array.isArray(grid.itemIds) ? grid.itemIds : [];
        const finalItemIds = new Array(gridSize).fill(null);
        // Only fill up to grid size
        for(let i = 0; i < Math.min(sourceIds.length, gridSize); i++) {
            finalItemIds[i] = sourceIds[i];
        }
        return finalItemIds.map(itemId => items.find(i => i.id === itemId) || null);
    }
    return new Array(gridSize).fill(null);
  }, [activeGridId, items, customGrids, debouncedSearchQuery, workerSearchResults, gridSize]);

  const paginatedItems = useMemo(() => {
      if (activeGridId !== 'All' && !debouncedSearchQuery.trim()) return itemsForDisplay;
      return itemsForDisplay.slice(0, displayLimit);
  }, [itemsForDisplay, displayLimit, activeGridId, debouncedSearchQuery]);

  // Infinite Scroll
  useEffect(() => {
    if ((activeGridId !== 'All' && !debouncedSearchQuery.trim()) || paginatedItems.length >= itemsForDisplay.length) return; 
    const observer = new IntersectionObserver(
        (entries) => {
            if (entries[0].isIntersecting) setDisplayLimit((prev) => prev + 20);
        },
        { threshold: 0.1, rootMargin: '100px' }
    );
    if (loadMoreRef.current) observer.observe(loadMoreRef.current);
    return () => observer.disconnect();
  }, [paginatedItems.length, itemsForDisplay.length, activeGridId, debouncedSearchQuery]);

  const handleAssignItem = useCallback((item: Item) => {
      if (!assigningSlot) return;
      const grid = customGrids.find(g => g.id === assigningSlot.gridId);
      if (grid) {
          const newItemIds = [...(grid.itemIds || [])];
          // Ensure array is large enough
          while (newItemIds.length < gridSize) newItemIds.push(null);
          newItemIds[assigningSlot.slotIndex] = item.id;
          updateCustomGrid({ ...grid, itemIds: newItemIds });
      }
      setIsSelectItemModalOpen(false);
      setAssigningSlot(null);
  }, [assigningSlot, customGrids, updateCustomGrid, gridSize]);

  const handleRemoveItemFromGrid = useCallback((slotIndex: number) => {
    if (activeGridId === 'All') return;
    const grid = customGrids.find(g => g.id === activeGridId);
    if (grid) {
        const newItemIds = [...(grid.itemIds || [])];
        while (newItemIds.length < gridSize) newItemIds.push(null);
        newItemIds[slotIndex] = null;
        updateCustomGrid({ ...grid, itemIds: newItemIds });
    }
  }, [activeGridId, customGrids, updateCustomGrid, gridSize]);

  // --- RENDER ---
  if (salesView === 'payment') {
    const sub = currentOrder.reduce((acc, i) => acc + i.price * i.quantity, 0);
    const t = settings.taxEnabled ? sub * (settings.taxRate / 100) : 0;
    return <ChargeScreen total={sub + t} tax={t} subtotal={sub} onBack={() => setSalesView('grid')} onProcessPayment={handleProcessPayment} onNewSale={() => { setSalesView('grid'); setPaymentResult(null); clearOrder(); setEditingTicket(null); }} paymentResult={paymentResult} orderItems={currentOrder} />;
  }

  const subtotal = currentOrder.reduce((sum, item) => sum + item.price * item.quantity, 0);
  const tax = settings.taxEnabled ? subtotal * (settings.taxRate / 100) : 0;
  const total = subtotal + tax;
  const isViewingAll = activeGridId === 'All' || debouncedSearchQuery.trim().length > 0;

  return (
    <div className="flex h-full w-full bg-background font-sans relative overflow-hidden">
      <div className="flex-1 flex flex-col min-w-0 h-full relative">
        <SalesHeader 
            openDrawer={openDrawer} 
            onSearchChange={setSearchQuery} 
            searchQuery={searchQuery} 
            storeName={settings.storeName}
        />

        <div className="flex-1 relative overflow-hidden">
            <div 
              ref={scrollContainerRef} 
              className="absolute inset-0 overflow-y-auto overflow-x-hidden p-2 md:p-4 scroll-smooth"
              style={{ WebkitOverflowScrolling: 'touch', transform: 'translateZ(0)' }}
            >
              {items.length === 0 && !debouncedSearchQuery.trim() ? (
                <div className="flex flex-col items-center justify-center h-full text-center text-text-secondary p-4">
                  <div className="max-w-md">
                    <ItemsIcon className="h-16 w-16 mx-auto text-gray-300 dark:text-gray-600" />
                    <h2 className="mt-4 text-xl font-semibold text-text-primary">Your Menu is Empty</h2>
                    <button onClick={() => navigate('/items')} className="mt-6 px-6 py-3 bg-primary text-primary-content font-bold rounded-lg hover:bg-primary-hover shadow-md">Add Items</button>
                  </div>
                </div>
              ) : (
                <div className={`pb-24 md:pb-0 ${!isViewingAll ? 'md:h-full' : 'md:pb-4'}`}>
                    <ItemGrid
                        itemsForDisplay={paginatedItems}
                        mode={isViewingAll ? 'all' : 'grid'}
                        onAddItemToOrder={handleItemClick}
                        onAssignItem={(idx) => { if(activeGridId !== 'All') { setAssigningSlot({ gridId: activeGridId, slotIndex: idx }); setIsSelectItemModalOpen(true); } }}
                        onRemoveItem={handleRemoveItemFromGrid}
                        isEditing={!isViewingAll && isGridEditing}
                        loadMoreRef={isViewingAll ? loadMoreRef : undefined}
                    />
                </div>
              )}
            </div>
        </div>

        {currentOrder.length > 0 && (
            <div className="md:hidden absolute bottom-[50px] left-0 right-0 p-4 z-50 pointer-events-none">
                <button 
                    onClick={() => setIsTicketVisible(true)}
                    className="w-full bg-primary text-primary-content rounded-xl shadow-xl shadow-primary/30 flex items-center justify-between p-4 active:opacity-90 transition-opacity pointer-events-auto"
                >
                    <div className="flex items-center gap-3">
                        <span className="bg-white/20 px-2.5 py-1 rounded-md text-sm font-bold backdrop-blur-sm">
                            {currentOrder.reduce((acc, item) => acc + item.quantity, 0)}
                        </span>
                        <span className="font-bold text-sm uppercase tracking-wide">View Cart</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <span className="font-bold text-lg">₹{total.toFixed(2)}</span>
                        <SalesIcon className="h-5 w-5 opacity-80" />
                    </div>
                </button>
            </div>
        )}

        <div className="bg-surface border-t border-border z-40 flex-shrink-0 relative shadow-sm">
             <CategoryTabs
                grids={customGrids}
                activeGridId={activeGridId}
                setActiveGridId={setActiveGridId}
                onAddNew={() => setIsAddGridModalOpen(true)}
                onManage={() => setIsManageGridsModalOpen(true)}
                isSearchActive={debouncedSearchQuery.trim().length > 0}
                searchResultsCount={itemsForDisplay.length}
                searchQuery={searchQuery}
                isEditing={isGridEditing}
                onToggleEditMode={() => setIsGridEditing(prev => !prev)}
              />
        </div>
      </div>

      <div className={`fixed inset-0 z-[60] bg-background flex flex-col transition-transform duration-300 ease-out will-change-transform md:static md:z-auto md:w-[320px] lg:w-[380px] md:border-l md:border-border md:translate-y-0 ${isTicketVisible ? 'translate-y-0' : 'translate-y-full'}`}>
        <Ticket
          className="w-full h-full flex flex-col"
          onClose={() => setIsTicketVisible(false)} 
          currentOrder={currentOrder} 
          editingTicket={editingTicket}
          savedTickets={savedTickets} 
          settings={settings} 
          total={total} 
          subtotal={subtotal} 
          tax={tax}
          printers={printers}
          editingQuantityItemId={editingQuantityItemId} 
          tempQuantity={tempQuantity} 
          setEditingQuantityItemId={setEditingQuantityItemId}
          setTempQuantity={(v) => /^\d*$/.test(v) && setTempQuantity(v)} 
          removeFromOrder={removeFromOrder} 
          deleteLineItem={deleteLineItem}
          updateOrderItemQuantity={updateOrderItemQuantity}
          handleQuantityClick={handleQuantityClick} 
          handleQuantityChangeCommit={handleQuantityChangeCommit}
          handleQuantityInputChange={(e) => /^\d*$/.test(e.target.value) && setTempQuantity(e.target.value)}
          handleQuantityInputKeyDown={(e) => { if (e.key === 'Enter') handleQuantityChangeCommit(); else if (e.key === 'Escape') setEditingQuantityItemId(null); }}
          handlePrimarySaveAction={() => {
              if (editingTicket) {
                  saveTicket({ ...editingTicket, items: currentOrder });
                  clearOrder();
                  setEditingTicket(null);
                  setIsTicketVisible(false);
              } else {
                  setPendingPrintAction(false);
                  setIsSaveModalOpen(true);
              }
          }}
          onCharge={() => setSalesView('payment')} 
          onOpenTickets={() => setIsOpenTicketsModalOpen(true)}
          onSaveTicket={() => { setPendingPrintAction(false); setIsSaveModalOpen(true); }} 
          onClearTicket={() => { clearOrder(); setEditingTicket(null); setEditingQuantityItemId(null); }}
          onPrintRequest={async () => {
              if (editingTicket) {
                  const updated = { ...editingTicket, items: [...currentOrder], lastModified: Date.now() };
                  await saveTicket(updated);
                  // Add logic here to call print util
                  clearOrder();
                  setEditingTicket(null);
                  if (window.innerWidth < 768) setIsTicketVisible(false);
              } else {
                  setPendingPrintAction(true);
                  setIsSaveModalOpen(true);
              }
          }}
        />
      </div>

      <SaveTicketModal 
        isOpen={isSaveModalOpen} 
        onClose={() => { setIsSaveModalOpen(false); setPendingPrintAction(false); }} 
        onSave={(name) => {
            const itemsToSave = [...currentOrder];
            saveTicket({ id: `T${Date.now()}`, name, items: itemsToSave }); 
            clearOrder(); 
            setEditingTicket(null); 
            setIsSaveModalOpen(false); 
            if (pendingPrintAction) {
                // Print logic stub
                setPendingPrintAction(false); 
            }
        }} 
        editingTicket={editingTicket} 
      />
      <OpenTicketsModal 
        isOpen={isOpenTicketsModalOpen} 
        tickets={savedTickets} 
        onClose={() => setIsOpenTicketsModalOpen(false)} 
        onLoadTicket={(t) => {
            if (currentOrder.length > 0) {
                setConfirmModalState({
                    isOpen: true,
                    title: 'Replace Current Order?',
                    message: 'Loading a saved ticket will replace your current unsaved order.',
                    onConfirm: () => { loadOrder(t.items); setEditingTicket(t); setIsOpenTicketsModalOpen(false); if(window.innerWidth < 768) setIsTicketVisible(true); },
                    confirmText: 'Yes, Load',
                    confirmButtonClass: 'bg-amber-500'
                });
            } else {
                loadOrder(t.items);
                setEditingTicket(t);
                setIsOpenTicketsModalOpen(false);
                if(window.innerWidth < 768) setIsTicketVisible(true);
            }
        }} 
        onDeleteTicket={removeTicket} 
      />
      <SelectItemModal isOpen={isSelectItemModalOpen} onClose={() => setIsSelectItemModalOpen(false)} onSelect={handleAssignItem} allItems={items} />
      <ManageGridsModal isOpen={isManageGridsModalOpen} onClose={() => setIsManageGridsModalOpen(false)} initialGrids={customGrids} onSave={(gs) => { setCustomGrids(gs); setIsManageGridsModalOpen(false); }} />
      <AddGridModal isOpen={isAddGridModalOpen} onClose={() => setIsAddGridModalOpen(false)} onSave={(n) => { const id = generateId(); addCustomGrid({id, name: n, itemIds: []}); setIsAddGridModalOpen(false); setActiveGridId(id); setIsGridEditing(true); }} />

      <PriceInputModal isOpen={!!variablePriceItem} onClose={() => setVariablePriceItem(null)} onConfirm={handleVariablePriceConfirm} item={variablePriceItem} />

      <ConfirmModal isOpen={confirmModalState.isOpen} onClose={() => setConfirmModalState(prev => ({ ...prev, isOpen: false }))} onConfirm={() => { confirmModalState.onConfirm(); setConfirmModalState(prev => ({ ...prev, isOpen: false })); }} title={confirmModalState.title} confirmText={confirmModalState.confirmText} confirmButtonClass={confirmModalState.confirmButtonClass}>{confirmModalState.message}</ConfirmModal>
    </div>
  );
};

